"use strict";(globalThis.webpackChunkc4_skills_docs=globalThis.webpackChunkc4_skills_docs||[]).push([[150],{6209(e,t,n){n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>a,default:()=>h,frontMatter:()=>o,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"examples/adr-postgresql","title":"ADR: PostgreSQL over MongoDB","description":"A complete, worked Architecture Decision Record for the fictional Internet Banking System. This demonstrates the full MADR template as produced by adr-scribe in Interview mode.","source":"@site/docs/examples/adr-postgresql.md","sourceDirName":"examples","slug":"/examples/adr-postgresql","permalink":"/c4-skills/examples/adr-postgresql","draft":false,"unlisted":false,"editUrl":"https://github.com/muthub-ai/c4-skills/tree/main/docs/docs/examples/adr-postgresql.md","tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"mainSidebar","previous":{"title":"Internet Banking System","permalink":"/c4-skills/examples/banking-system"},"next":{"title":"Mermaid Errors","permalink":"/c4-skills/troubleshooting/mermaid-errors"}}');var r=n(4848),i=n(8453);const o={sidebar_position:2},a="ADR: PostgreSQL over MongoDB",d={},l=[{value:"Full ADR Output",id:"full-adr-output",level:2},{value:"What makes this ADR good",id:"what-makes-this-adr-good",level:2}];function c(e){const t={code:"code",em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"adr-postgresql-over-mongodb",children:"ADR: PostgreSQL over MongoDB"})}),"\n",(0,r.jsxs)(t.p,{children:["A complete, worked Architecture Decision Record for the fictional Internet Banking System. This demonstrates the full MADR template as produced by ",(0,r.jsx)(t.code,{children:"adr-scribe"})," in ",(0,r.jsx)(t.strong,{children:"Interview mode"}),"."]}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.strong,{children:"Prompt used:"})}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{children:"Act as the adr-scribe. We just decided to use PostgreSQL instead of MongoDB\nfor the Payments API. We need ACID transactions.\n"})}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"full-adr-output",children:"Full ADR Output"}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-markdown",children:"# Use PostgreSQL over MongoDB for Payments API\n\n* Status: Accepted\n* Date: 2026-04-26\n\n## Context\n\nThe Payments API handles financial transactions that require multi-step\natomicity: debit one account, credit another, and log the event \u2014 all\nin a single atomic operation. If any step fails, the entire transaction\nmust be rolled back.\n\nMongoDB 6.0 introduced multi-document transactions, but our current\nMongoDB version (4.4) does not support them. An upgrade is possible but\ncarries significant risk given the volume of existing production data.\nPostgreSQL offers first-class ACID transaction support and is well-suited\nto structured financial data with clear relational constraints.\n\nKey forces:\n- Financial data requires ACID guarantees (non-negotiable)\n- Engineering team has deep PostgreSQL expertise\n- Time-to-market pressure makes a complex migration unattractive\n\n## Considered Options\n\n* **PostgreSQL 15** \u2014 Mature relational database with full ACID support\n* **MongoDB 4.4** \u2014 Current production database, no multi-document transactions\n* **MongoDB 6.0 (upgrade)** \u2014 Adds multi-document transactions, but requires\n  a major version migration with downtime risk\n* **CockroachDB** \u2014 Distributed SQL with ACID support, but unfamiliar to the team\n\n## Decision Outcome\n\nChosen option: **PostgreSQL 15**, because it provides the ACID transaction\nguarantees required for financial operations, eliminates the multi-document\ntransaction problem without a risky database upgrade, and aligns with the\nteam's existing expertise.\n\n### Positive Consequences\n\n* Full ACID compliance eliminates the risk of partial transaction records\n  (e.g., debit recorded, credit missing).\n* No major version migration risk \u2014 fresh schema on a proven platform.\n* Team can leverage existing PostgreSQL knowledge (indexing, query optimization,\n  connection pooling with pgBouncer).\n* Structured schema enforces data integrity at the database level.\n\n### Negative Consequences\n\n* **Schema migrations** require careful coordination as the data model evolves.\n  MongoDB's schema-less nature made ad-hoc field additions trivial.\n* **Horizontal scaling** is more complex. PostgreSQL scales vertically by default;\n  horizontal sharding requires additional tooling (Citus, read replicas).\n* **JSON document storage** is more awkward in PostgreSQL than MongoDB, which may\n  matter for flexible metadata fields on transactions.\n* Existing MongoDB data for non-payment collections (user preferences, audit logs)\n  will remain on MongoDB, creating a **polyglot persistence** situation that\n  increases operational complexity.\n"})}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"what-makes-this-adr-good",children:"What makes this ADR good"}),"\n",(0,r.jsxs)(t.table,{children:[(0,r.jsx)(t.thead,{children:(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.th,{children:"\u2705"}),(0,r.jsx)(t.th,{children:"Reason"})]})}),(0,r.jsxs)(t.tbody,{children:[(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:(0,r.jsx)(t.strong,{children:"4 options listed"})}),(0,r.jsx)(t.td,{children:"Shows the decision was genuinely evaluated, not a foregone conclusion"})]}),(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:(0,r.jsx)(t.strong,{children:"Specific version numbers"})}),(0,r.jsx)(t.td,{children:"PostgreSQL 15, MongoDB 4.4 \u2014 removes ambiguity"})]}),(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:(0,r.jsx)(t.strong,{children:"Context explains the forces"})}),(0,r.jsxs)(t.td,{children:['Not just "we need transactions" \u2014 explains ',(0,r.jsx)(t.em,{children:"why"})," the current setup fails"]})]}),(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:(0,r.jsx)(t.strong,{children:"4 negative consequences"})}),(0,r.jsx)(t.td,{children:"Honest about trade-offs; no free lunch presented"})]}),(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:(0,r.jsx)(t.strong,{children:"Cross-references polyglot persistence"})}),(0,r.jsx)(t.td,{children:"Flags the new operational complexity introduced"})]})]})]})]})}function h(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(c,{...e})}):c(e)}}}]);